        @Override
        public void handleMessage(SoapMessage message) throws Fault {
            try {
                RawSoapContext ctx = new RawSoapContext();

                Document doc = null;
                Object node = message.getContent(Node.class);
                if (node instanceof Document) doc = (Document) node;
                else if (node instanceof Element) doc = ((Element) node).getOwnerDocument();

                if (doc == null) {
                    SOAPMessage sm = message.getContent(SOAPMessage.class);
                    if (sm != null) {
                        Source src = sm.getSOAPPart().getContent();
                        DOMResult res = new DOMResult();
                        Transformer t = TransformerFactory.newInstance().newTransformer();
                        t.transform(src, res);
                        Node n = res.getNode();
                        if (n instanceof Document) doc = (Document) n;
                        else if (n != null) doc = n.getOwnerDocument();
                    }
                }

                ctx.document = doc;
                if (doc != null) {
                    Transformer t = TransformerFactory.newInstance().newTransformer();
                    java.io.StringWriter sw = new java.io.StringWriter();
                    t.transform(new DOMSource(doc), new StreamResult(sw));
                    ctx.rawSoap = sw.toString();
                }

                message.getExchange().put(RawSoapContext.class.getName(), ctx);
                message.put(RawSoapContext.class.getName(), ctx);
            } catch (Exception e) {
                throw new Fault(e);
            }
        }
